-- Correlated (slow): runs once per employee
SELECT name FROM employees e
WHERE salary > (SELECT AVG(salary) FROM employees WHERE dept = e.dept);

WITH dept_avg AS (
  SELECT dept, AVG(salary) as avg_sal FROM employees GROUP BY dept
)
SELECT e.name, e.salary, d.avg_sal
FROM employees e JOIN dept_avg d ON e.dept = d.dept
WHERE e.salary > d.avg_sal;

-- Covering index for: SELECT name, email FROM users WHERE status='ACTIVE'
CREATE INDEX idx_covering ON users(status, name, email);
-- 'Using index' in EXPLAIN -- no table lookup needed
